async (params, browser) => {
  // Open leaderboard page
  await browser.open(`https://www.kaggle.com/competitions/${params.competition_slug}/leaderboard`)

  // Wait for leaderboard table
  await browser.waitForSelector('table, [role=\'table\'], [role=\'grid\'], [role=\'main\']', 15000)

  // Let leaderboard render
  await browser.wait(3000)

  // Scroll for more entries
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract leaderboard data
  const page_data = await browser.evaluate(`const entries = []; const table = document.querySelector('table'); if (table) { const rows = table.querySelectorAll('tbody tr'); rows.forEach((row, i) => { const cells = Array.from(row.querySelectorAll('td')).map(c => c.textContent.trim()); const link = row.querySelector('a'); const scoreCell = cells.find(t => t.match(/^-?\d+\.?\d*$/)); entries.push({ rank: cells[0] || String(i + 1), team: link ? link.textContent.trim() : (cells[1] || ''), score: scoreCell || '', entries_count: cells[cells.length - 1] || '' }); }); } else { document.querySelectorAll('[role="row"], li[class]').forEach((row, i) => { const text = row.textContent.trim(); const link = row.querySelector('a'); const numbers = text.match(/\d+\.?\d*/g) || []; entries.push({ rank: numbers[0] || String(i + 1), team: link ? link.textContent.trim() : text.substring(0, 100), score: numbers.find(n => n.includes('.')) || numbers[1] || '' }); }); } const totalMatch = document.body.innerText.match(/(\d[\d,]*)\s*teams?/i); return { competition: '' + params.competition_slug + '', total_teams: totalMatch ? totalMatch[1] : '', entries_count: entries.length, leaderboard: entries.slice(0, 50), url: window.location.href };`)

  return page_data
}
